    $fx.Secrets | ConvertTo-Json -Depth 5 | Set-Content -LiteralPath (Join-Path $temp 'secrets.json') -Encoding utf8
    $fx.AsOf | Set-Content -LiteralPath (Join-Path $temp '.as-of') -Encoding utf8 -NoNewline

